VALUES
  ('heelevel3-4c199b1b-moex-00063', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列關於保證契約之敘述，何者錯誤？', '["保證人之先訴抗辯權，得預先拋棄", "主債務人已拋棄之抗辯，保證人不得主張", "主債務人債務履行遲延時，保證人得向其請求除去保證責任", "數人保證同一債務時，原則上應負連帶責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00064', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲、乙、丙以合夥方式經營事業，下列敘述，何者正確？', '["民法所稱合夥，係指3人以上互約出資，以經營共同事業之契約", "甲、乙、丙之出資，屬於其分別共有", "乙欲以勞務為出資，但因民法合夥契約之規定，無法為之", "事業經營中，若有發生損害而導致資本減少，原則上甲、乙、丙並無補充資本之義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00065', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲向乙租屋，租期3年，下列敘述，何者正確？', '["甲與乙約定，其租約無民法第425條第1項有關所有權讓與不破租賃規定之適用，該約定有效", "該租約不以字據訂立為必要", "甲與乙若約定，不得將房屋之一部分轉租他人，該約定無效", "甲有任意終止權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00066', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲之轎車引擎故障，甲偷乙之轎車引擎，裝置於甲之轎車上，下列敘述，何者正確？', '["乙之轎車引擎與甲之轎車附合，甲取得乙之轎車引擎之所有權", "乙之轎車引擎與甲之轎車混合，甲取得乙之轎車引擎之所有權", "乙之轎車引擎與甲之轎車並未附合，甲未取得乙之轎車引擎所有權", "乙不得依所有物返還請求權之規定，請求甲返還乙之轎車引擎 32820、33320 33620"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00067', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '甲向乙借新臺幣1,000萬元，以甲所有之A地為乙設定普通抵押權，嗣後甲將A地出租並交付於丙。 債務清償期屆至，甲無力清償債務，乙聲請法院拍賣A地，由丁順利拍定取得A地之所有權。下列 敘述，何者正確？', '["甲丙之租賃關係變成丙丁之租賃關係", "甲丙之租賃關係應由法院依職權終止", "甲丙之租賃關係應由法院依聲請終止", "甲丙之租賃關係得由法院依聲請或職權終止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00068', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列何者非屬留置權消滅之原因？', '["債務人或留置物所有人為債務之清償，已提出相當之擔保者", "留置權人將留置物返還於留置物所有人或交付於債務人者", "留置權人喪失其留置物之占有，於2年內未請求返還者", "留置權所擔保之債權罹於消滅時效者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00069', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '依民法規定，下列關於物權優先效力之敘述，何者正確？', '["擔保物權優先於用益物權", "性質相容得併存之動產物權間，適用時間原則，成立在先者，優先於成立在後者", "不動產物權優先於動產物權", "登記優先於占有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00070', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列關於認領之敘述，何者正確？', '["有事實足認其為非婚生子女之生父者，非婚生子女得向生父提起強制認領之訴", "非婚生子女經生母撫育者，視為認領", "胎兒既尚未出生，無受認領之權利", "生父死亡後亦得向其繼承人提起認領之訴，惟此權利自生父死亡後2年間不行使而消滅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00071', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列關於拋棄繼承之敘述，何者正確？', '["繼承人經其他繼承人全體同意者，得拋棄繼承", "拋棄繼承，應於知悉其得繼承之時起3個月內，以書面向法院為之", "拋棄繼承後，應通知因其拋棄而應為繼承之人。未為通知者，不生拋棄繼承之效力", "繼承之拋棄，自拋棄時起，發生效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('heelevel3-4c199b1b-moex-00072', 'heelevel3-4c199b1b', 'heelevel3-4c199b1b-moex-112-9b7ab1bb', 'sub-heelevel3-4c199b1b-01', NULL, 'single_choice', '下列關於遺囑執行之敘述，何者正確？', '["未成年人、受監護宣告或輔助宣告之人，得於法定代理人見證下，受指定為遺囑執行人", "遺囑人得以遺囑指定遺囑執行人，或委託他人指定之", "有封緘之遺囑，非經數繼承人其中之1人聲請鄉（鎮、區）公所公開進行開視程序，不得逕由全 體繼承人共同開視之", "數繼承人其中之1人於被繼承人之配偶與被繼承人之全體債權人書面同意後，得處分其與遺囑 有關之遺產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "4ce894540716", "answer_pdf_sha1": "dd8608dbb661", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "消費者保護"}'::jsonb, NULL)
